urlset:

  {{ config.url }}/
  {{ sNow.toISOString() }}

{% for post in posts %}
{% if post.path.indexOf('secure/') !== 0 and post.path.indexOf('contact/') !== 0 and post.path.indexOf('opt-images/') !== 0 %}

  {{ post.permalink }}
  {% if post.updated %}
  {{ post.updated.toISOString() }}
  {% endif %}

{% endif %}
{% endfor %}
